import fs from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

export async function syncSystemPrompt(
  root = path.resolve(import.meta.dirname, '..'),
) {
  const sourcePath = path.join(root, 'system-prompt.md');
  const outputPath = path.join(root, 'src', 'system-prompt.generated.mjs');

  const markdown = await fs.readFile(sourcePath, 'utf8');
  const generated = [
    '// Generated from ../system-prompt.md by scripts/sync-system-prompt.mjs.',
    '// Do not edit this file directly.',
    '',
    `export const DEFAULT_SYSTEM_PROMPT = ${JSON.stringify(markdown)};`,
    '',
  ].join('\n');

  await fs.writeFile(outputPath, generated, 'utf8');
}

const isEntrypoint =
  process.argv[1] &&
  path.resolve(process.argv[1]) ===
    path.resolve(fileURLToPath(import.meta.url));
if (isEntrypoint) {
  await syncSystemPrompt();
}
